#include<bits/stdc++.h>
using namespace std;
map<long long,int>mp;
int main()
{
	long long n;
	cin>>n;
	for(long long i=2;i*i<=n;i++){//分解质因数 
		while(n%i==0){
			n/=i;
			mp[i]++;
		}
	}
	if(n>1)mp[n]++;//如果没分完，就把剩下的单独拿出来成为一个质因数 p.s.: 131=2*2*2*2*2*2*2*3 
	int ans=0;
	for(auto[u,v]:mp){
		for(int i=1;i<=v;i++){//把足够多的质因数分解：64=2*2*2*2*2*2=2*4*8（2,4,8是奇妙数字） 
			v-=i;
			ans++;
		}
	}
	cout<<ans<<endl;
}
